import React, { useState } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import Navbar from './components/Navbar/Navbar';
import Footer from './components/Footer/Footer';
import Hero from './features/landing/Hero';
import HowItWorks from './features/landing/HowItWorks';
import JobListContainer from './features/eksplorasi/JobListContainer';
import Login from './components/auth/Login';

const App = () => {
    const [isAuthenticated, setIsAuthenticated] = useState(!!localStorage.getItem('token'));
    const [activeMenu, setActiveMenu] = useState('eksplorasi');

    return (
        <Router>
            <div style={{ display: 'flex', flexDirection: 'column', minHeight: '100vh', background: '#080402' }}>
                <Navbar isAuthenticated={isAuthenticated} activeMenu={activeMenu} setActiveMenu={setActiveMenu} handleLogout={() => { /* logic logout */ }} />

                <main style={{ flex: 1 }}>
                    <Routes>
                        <Route path="/" element={
                            <>
                                {/* Jika Guest, Tampilkan Landing Page */}
                                {!isAuthenticated && (
                                    <>
                                        <Hero />
                                        <HowItWorks />
                                    </>
                                )}
                                {/* List Pekerjaan tetap muncul */}
                                <div style={{ padding: '40px 80px' }}>
                                    <JobListContainer />
                                </div>
                            </>
                        } />
                        <Route path="/login" element={<Login onLoginSuccess={() => setIsAuthenticated(true)} />} />
                    </Routes>
                </main>
                <Footer />
            </div>
        </Router>
    );
};

export default App;
